import * as http from 'node:http';
import { z } from 'zod';
import {
  IPC_TIMEOUTS_MS,
  IpcErrorEnvelopeSchema,
  LlmCallResponseSchema,
  SessionNextMessageResponseSchema,
  ToolExecuteHostResponseSchema,
  ToolListResponseSchema,
  ToolPreCallResponseSchema,
