import type {
  ChatMessage,
  LlmCallResponse,
  ToolCall,
  ToolDescriptor,
  ToolExecuteHostResponse,
  ToolPreCallResponse,
} from '@ax/ipc-protocol';

// ---------------------------------------------------------------------------
// Sandbox-side turn loop.
//
// This is a faithful port of @ax/core/src/chat-loop.ts into the sandbox
// process. The differences:
//
