async function runOneToolCall(
  history: ChatMessage[],
  deps: TurnLoopDeps,
  toolCall: ToolCall,
): Promise<void> {
  const pre = (await deps.client.call('tool.pre-call', {
    call: toolCall,
  })) as ToolPreCallResponse;

  if (pre.verdict === 'reject') {
    history.push({
      role: 'user',
      content: `tool '${toolCall.name}' rejected: ${pre.reason}`,
