### Create Custom MCP Tools using TypeScript and Python

Source: https://context7.com/nothflare/claude-agent-sdk-docs/llms.txt

Create in-process MCP servers with custom tools to extend Claude's capabilities. This example shows how to define a custom tool for fetching weather information.

```typescript
import { query, tool, createSdkMcpServer } from "@anthropic-ai/claude-agent-sdk";
import { z } from "zod";

const customServer = createSdkMcpServer({
  name: "my-tools",
  version: "1.0.0",
  tools: [
    tool(
      "get_weather",
      "Get current temperature for a location",
      {
        latitude: z.number().describe("Latitude"),
        longitude: z.number().describe("Longitude")
      },
      async (args) => {
        const response = await fetch(
          `https://api.open-meteo.com/v1/forecast?latitude=${args.latitude}&longitude=${args.longitude}&current=temperature_2m`
        );
        const data = await response.json();
        return {
          content: [{ type: "text", text: `Temperature: ${data.current.temperature_2m}°C` }]
        };
      }
    )
  ]
});

async function* generateMessages() {
  yield { type: "user", message: { role: "user", content: "What's the weather in Paris?" } };
}

for await (const message of query({
  prompt: generateMessages(),
  options: {
    mcpServers: { "my-tools": customServer },
    allowedTools: ["mcp__my-tools__get_weather"]
  }
})) {
  if (message.type === "result") console.log(message.result);
}
```

```python
import asyncio
import aiohttp
from claude_agent_sdk import tool, create_sdk_mcp_server, ClaudeSDKClient, ClaudeAgentOptions

@tool("get_weather", "Get current temperature", {"latitude": float, "longitude": float})
async def get_weather(args):
    async with aiohttp.ClientSession() as session:
        url = f"https://api.open-meteo.com/v1/forecast?latitude={args['latitude']}&longitude={args['longitude']}&current=temperature_2m"
        async with session.get(url) as response:
            data = await response.json()
    return {"content": [{"type": "text", "text": f"Temperature: {data['current']['temperature_2m']}°C"}]}

custom_server = create_sdk_mcp_server(name="my-tools", version="1.0.0", tools=[get_weather])

async def main():
    options = ClaudeAgentOptions(
        mcp_servers={"my-tools": custom_server},
        allowed_tools=["mcp__my-tools__get_weather"]
    )
    async with ClaudeSDKClient(options=options) as client:
        await client.query("What's the weather in Paris?")
        async for msg in client.receive_response():
            print(msg)

asyncio.run(main())
```

